# src/pricing.py — the code to be tested
def apply_discount(price: float, user_type: str) -> float:
    """Apply discount based on user type."""
    if price <= 0:
        raise ValueError(f"Price must be positive, got {price}")
    if user_type == "premium":
        return price * 0.80   # 20% discount
    elif user_type == "student":
        return price * 0.90   # 10% discount
    else:
        return price          # no discount


# tests/test_pricing.py
import pytest
from src.pricing import apply_discount

# Test happy paths — covers 3 branches
def test_premium_user():
    assert apply_discount(100.0, "premium") == 80.0

def test_student_user():
    assert apply_discount(100.0, "student") == 90.0

def test_regular_user():
    assert apply_discount(100.0, "regular") == 100.0

# Test edge case — covers the error branch
def test_invalid_price():
    with pytest.raises(ValueError):
        apply_discount(-10.0, "premium")

# Without the ValueError test, branch coverage would be < 100%
# because the 'price <= 0' branch would never be taken

# src/classifier.py
def classify_temperature(temp_celsius: float) -> str:
    """Classify temperature into categories."""
    if temp_celsius < 0:
        return "freezing"
    elif temp_celsius < 15:
        return "cold"
    elif temp_celsius < 25:
        return "comfortable"
    elif temp_celsius < 35:
        return "warm"
    else:
        return "hot"


# tests/test_classifier.py
import pytest
from src.classifier import classify_temperature

@pytest.mark.parametrize("temp,expected", [
    (-10,  "freezing"),    # branch 1: temp < 0
    (5,    "cold"),        # branch 2: 0 <= temp < 15
    (20,   "comfortable"), # branch 3: 15 <= temp < 25
    (30,   "warm"),        # branch 4: 25 <= temp < 35
    (40,   "hot"),         # branch 5: temp >= 35
    (0,    "cold"),        # boundary: exactly 0
    (14.9, "cold"),        # boundary: just below 15
    (15.0, "comfortable"), # boundary: exactly 15
])
def test_classify_temperature(temp, expected):
    assert classify_temperature(temp) == expected

# Run: pytest --cov=src --cov-branch tests/
# Branch coverage: measures that BOTH sides of each if/elif were exercised
